def verify_code_correctness(code: str, test_cases: list) -> dict:
    report = vex.verify({
        "type": "code_correctness",
        "code": code,
        "test_cases": test_cases,
        "language": "python",
        "frameworks": ["pytest", "unittest"]
    })

    return {
        "score": report['test_pass_rate'],
        "coverage": report['coverage'],
        "approved": report['test_pass_rate'] > 90
    }

