def security_scan(code: str, dependencies: list) -> dict:
    report = vex.verify({
        "type": "security_suite",
        "code": code,
        "dependencies": dependencies,
        "scans": [
            "secrets",
            "vulnerabilities",
            "license_compliance",
            "dependency_safety"
        ]
    })

    issues = []
    if report['secrets']['found']:
        issues.append("Secrets detected")
    if report['vulnerabilities']['critical'] > 0:
        issues.append("Critical vulnerabilities")

    return {
        "approved": len(issues) == 0,
        "issues": issues,
        "security_score": report['overall_score']
    }

